import React, { useState, useRef, useEffect, useMemo } from 'react';
import { 
  FileText, 
  Upload, 
  CheckCircle2, 
  XCircle, 
  AlertCircle, 
  User, 
  FilePlus, 
  Loader2,
  ChevronRight,
  Info,
  Download,
  Files,
  RotateCcw,
  Trash2,
  Volume2,
  Plus,
  Archive,
  Clock,
  Globe
} from 'lucide-react';
import { motion, AnimatePresence } from 'motion/react';
import JSZip from 'jszip';
import { analyzeGraduationDocuments, AnalysisResponse, VerificationResult } from './services/gemini';
import { reorderPdf, generateOrderedPdfWithTOC } from './services/pdfUtils';

interface FileWithStatus {
  id: string;
  file: File;
  base64: string | null;
  loading: boolean;
  result: AnalysisResponse | null;
  error: string | null;
  responsible: string;
  studentName: string;
}
const LOGO_ESCUELA_NAVAL = "data:image/png;base64,"; 

export default function App() {
  const [files, setFiles] = useState<FileWithStatus[]>([]);
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [activeView, setActiveView] = useState<'individual' | 'summary'>('individual');
  const [isBatchProcessing, setIsBatchProcessing] = useState(false);
  const [isDownloadingZip, setIsDownloadingZip] = useState(false);
  const [globalError, setGlobalError] = useState<string | null>(null);
  const [isDragging, setIsDragging] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  useEffect(() => {
    audioRef.current = new Audio('https://assets.mixkit.co/active_storage/sfx/2869/2869-preview.mp3');
  }, []);

  const playSuccessSound = () => {
    if (audioRef.current) {
      audioRef.current.play().catch(e => console.error("Error playing sound:", e));
    }
  };

  const processFiles = async (fileList: File[]) => {
    const newFiles: FileWithStatus[] = [];
    
    for (const file of fileList) {
      if (file.type !== 'application/pdf') {
        setGlobalError('Solo se permiten archivos PDF.');
        continue;
      }
      
      const id = Math.random().toString(36).substring(7);
      
      if (file.size > 20 * 1024 * 1024) {
        setGlobalError(`El archivo ${file.name} es demasiado grande (máx 20MB).`);
        continue;
      }

      const fileName = file.name.replace(/\.[^/.]+$/, ""); // Remove extension
      const parts = fileName.split('_');
      
      // Student name is before the first _
      const studentName = parts[0].trim().toUpperCase().replace(/_/g, ' ');
      
      let extractedResponsible = 'NO HAY RESPONSABLE';
      
      if (parts.length > 1) {
        // Responsible is after the first _
        const rawName = parts.slice(1).join('_').trim().toUpperCase();
        const words = rawName.split(/\s+/).filter(w => w.length > 0);
        const articles = ['DE', 'LA', 'EL', 'LOS', 'LAS', 'Y', 'DEL', 'DI', 'DA'];
        let count = 0;
        let resultWords = [];
        for (const word of words) {
          resultWords.push(word);
          if (!articles.includes(word)) {
            count++;
          }
          if (count === 3) break;
        }
        extractedResponsible = resultWords.join(' ');
      }

      newFiles.push({
        id,
        file,
        base64: null,
        loading: false,
        result: null,
        error: null,
        responsible: extractedResponsible,
        studentName: studentName
      });
    }

    if (newFiles.length > 0) {
      setFiles(prev => [...prev, ...newFiles]);
      if (!selectedId) {
        setSelectedId(newFiles[0].id);
      }
      setGlobalError(null);
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      processFiles(Array.from(e.target.files));
      if (fileInputRef.current) fileInputRef.current.value = '';
    }
  };

  const dragCounter = useRef(0);

  const handleDragEnter = (e: React.DragEvent) => {
    e.preventDefault();
    dragCounter.current++;
    if (e.dataTransfer.items && e.dataTransfer.items.length > 0) {
      setIsDragging(true);
    }
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
  };

  const handleDragLeave = (e: React.DragEvent) => {
    e.preventDefault();
    dragCounter.current--;
    if (dragCounter.current === 0) {
      setIsDragging(false);
    }
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    dragCounter.current = 0;
    if (e.dataTransfer.files) {
      processFiles(Array.from(e.dataTransfer.files));
    }
  };

  const resetAll = () => {
    setFiles([]);
    setSelectedId(null);
    setGlobalError(null);
    setActiveView('individual');
  };

  const readFileAsBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.onload = () => {
        const base64String = (reader.result as string).split(',')[1];
        resolve(base64String);
      };
      reader.onerror = reject;
      reader.readAsDataURL(file);
    });
  };

  const removeFile = (id: string) => {
    setFiles(prev => prev.filter(f => f.id !== id));
    if (selectedId === id) {
      setSelectedId(null);
    }
  };

  const analyzeFile = async (id: string, silent: boolean = false) => {
    const fileData = files.find(f => f.id === id);
    if (!fileData || fileData.result) return true;

    if (!silent) {
      setActiveView('summary');
    }

    setFiles(prev => prev.map(f => f.id === id ? { ...f, loading: true, error: null } : f));

    try {
      let currentBase64 = fileData.base64;
      if (!currentBase64) {
        currentBase64 = await readFileAsBase64(fileData.file);
        // Store it for future use
        setFiles(prev => prev.map(f => f.id === id ? { ...f, base64: currentBase64 } : f));
      }

      const analysis = await analyzeGraduationDocuments(currentBase64);
      setFiles(prev => prev.map(f => f.id === id ? { ...f, loading: false, result: analysis } : f));
      
      if (!silent) {
        playSuccessSound();
      }
      
      return true;
    } catch (err: any) {
      console.error(err);
      let errorMessage = 'Error al analizar.';
      let isQuotaError = false;
      
      const errorString = JSON.stringify(err);
      if (errorString.includes('429') || errorString.includes('RESOURCE_EXHAUSTED') || (err.message && err.message.includes('quota'))) {
        errorMessage = 'Límite de uso excedido (Cuota). Por favor, espera un minuto e intenta de nuevo.';
        isQuotaError = true;
      }
      
      setFiles(prev => prev.map(f => f.id === id ? { ...f, loading: false, error: errorMessage } : f));
      if (isQuotaError) throw err;
      return false;
    }
  };

  const analyzeAll = async () => {
    const pendingFiles = files.filter(f => !f.result && !f.loading);
    if (pendingFiles.length === 0) return;

    setActiveView('summary');
    setIsBatchProcessing(true);
    try {
      for (const fileData of pendingFiles) {
        await analyzeFile(fileData.id, true);
        // Pequeña pausa para evitar saturar la API
        await new Promise(resolve => setTimeout(resolve, 100));
      }
      playSuccessSound();
    } catch (err) {
      console.error("Procesamiento por lotes detenido:", err);
    } finally {
      setIsBatchProcessing(false);
    }
  };

  const handleResponsibleChange = (id: string, value: string) => {
    setFiles(prev => prev.map(f => f.id === id ? { ...f, responsible: value } : f));
  };

  const downloadAllZip = async () => {
    if (files.length === 0) return;

    setIsDownloadingZip(true);
    const zip = new JSZip();
    const usedFilenames = new Map<string, number>();
    
    try {
      for (const fileData of files) {
        try {
          let finalFilename = "";
          let pdfBytes: Uint8Array | null = null;

          if (fileData.result && fileData.base64) {
            const studentName = fileData.result.personName || fileData.studentName;
            pdfBytes = await generateOrderedPdfWithTOC(
              fileData.base64, 
              fileData.result.checklist,
              studentName
            );
            
            // Base filename: APELLIDO_NOMBRE
            const baseName = studentName.replace(/\s+/g, '_').toUpperCase();
            finalFilename = `${baseName}.pdf`;
          } else {
            // If not analyzed, use original filename
            finalFilename = fileData.file.name;
          }

          // Handle duplicates
          if (usedFilenames.has(finalFilename)) {
            const count = usedFilenames.get(finalFilename)! + 1;
            usedFilenames.set(finalFilename, count);
            const nameParts = finalFilename.split('.');
            const ext = nameParts.pop();
            finalFilename = `${nameParts.join('.')} (${count}).${ext}`;
          } else {
            usedFilenames.set(finalFilename, 1);
          }

          if (pdfBytes) {
            zip.file(finalFilename, pdfBytes);
          } else {
            zip.file(finalFilename, fileData.file);
          }
        } catch (error) {
          console.error(`Error adding file to ZIP ${fileData.file.name}:`, error);
          // Fallback to original file on error with duplicate handling
          let fallbackName = fileData.file.name;
          if (usedFilenames.has(fallbackName)) {
            const count = usedFilenames.get(fallbackName)! + 1;
            usedFilenames.set(fallbackName, count);
            const nameParts = fallbackName.split('.');
            const ext = nameParts.pop();
            fallbackName = `${nameParts.join('.')} (${count}).${ext}`;
          } else {
            usedFilenames.set(fallbackName, 1);
          }
          zip.file(fallbackName, fileData.file);
        }
      }
      
      const content = await zip.generateAsync({ type: 'blob' });
      const url = URL.createObjectURL(content);
      const link = document.createElement('a');
      link.href = url;
      link.download = `REQUISITOS_GRADO_${new Date().toISOString().split('T')[0]}.zip`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      URL.revokeObjectURL(url);
    } catch (err) {
      console.error("Error generating ZIP:", err);
    } finally {
      setIsDownloadingZip(false);
    }
  };

  const handleDownloadReordered = async (fileData: FileWithStatus) => {
    if (!fileData.result) return;

    let base64 = fileData.base64;
    if (!base64) {
      base64 = await readFileAsBase64(fileData.file);
    }

    try {
      const ranges = fileData.result.checklist.map(item => item.pageRange);
      const pdfBytes = await reorderPdf(base64, ranges);
      
      const cleanName = fileData.result.personName
        .normalize("NFD")
        .replace(/[\u0300-\u036f]/g, "")
        .replace(/[^a-zA-Z0-9 ]/g, "")
        .trim()
        .toUpperCase();

      const cleanResponsible = fileData.responsible
        .normalize("NFD")
        .replace(/[\u0300-\u036f]/g, "")
        .replace(/[^a-zA-Z0-9 ]/g, "")
        .trim()
        .toUpperCase();
      
      const fileName = `${cleanName || 'SIN_NOMBRE'}_${cleanResponsible || 'SIN_RESPONSABLE'}.pdf`;

      const blob = new Blob([pdfBytes], { type: 'application/pdf' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = fileName;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      URL.revokeObjectURL(url);
    } catch (err) {
      console.error(err);
      setGlobalError('Error al generar el PDF ordenado.');
    }
  };

  const selectedFile = files.find(f => f.id === selectedId);

  const getMissingItems = (result: AnalysisResponse) => {
    return result.checklist
      .filter(item => item.status !== 'present')
      .map(item => item.item)
      .join(', ');
  };

  const isComplete = (result: AnalysisResponse) => {
    return result.checklist.every(item => item.status === 'present');
  };

  const filesWithIssues = useMemo(() => {
    return files.filter(f => f.error || (f.result && !isComplete(f.result)));
  }, [files]);

  return (
    <div 
      className="min-h-screen flex flex-col bg-portal-gradient text-white font-sans selection:bg-brand-light/20 relative"
      onDragEnter={handleDragEnter}
      onDragOver={handleDragOver}
      onDragLeave={handleDragLeave}
      onDrop={handleDrop}
    >
      {/* Global Matrix Rain Overlay */}
      <div className="fixed inset-0 pointer-events-none z-0 overflow-hidden opacity-10">
        {[...Array(20)].map((_, i) => (
          <div 
            key={`matrix-col-${i}`} 
            className="matrix-column" 
            style={{ 
              left: `${i * 5}%`, 
              animationDelay: `${Math.random() * 5}s`,
              animationDuration: `${4 + Math.random() * 4}s`
            }} 
          >
            {Array.from({ length: 20 }, () => Math.floor(Math.random() * 10)).join('')}
          </div>
        ))}
      </div>

      {/* Global Sparkles Overlay */}
      <div className="fixed inset-0 pointer-events-none z-0 overflow-hidden">
        {[...Array(40)].map((_, i) => (
          <div 
            key={`global-sparkle-${i}`} 
            className="sparkle-dot" 
            style={{ 
              top: `${Math.random() * 100}%`, 
              left: `${Math.random() * 100}%`, 
              animationDelay: `${Math.random() * 5}s`,
              transform: `scale(${0.4 + Math.random() * 0.8})`,
              opacity: 0.3 + Math.random() * 0.7
            }} 
          />
        ))}
      </div>

      {/* Header */}
      <header className="sticky top-0 z-50 bg-brand border-b border-white/10 shadow-2xl">
        <div className="max-w-[1400px] mx-auto px-6 h-20 flex items-center justify-between">
          <div className="flex items-center gap-4">
            <div className="w-16 h-16 flex items-center justify-center">
              <img 
                src={LOGO_ESCUELA_NAVAL} 
                alt="Logo Escuela Naval" 
                className="w-full h-full object-contain drop-shadow-[0_0_1px_rgba(255,255,255,1)]"
                referrerPolicy="no-referrer"
              />
            </div>
            <div className="hidden sm:block">
              <p className="text-[10px] font-bold text-brand-light uppercase tracking-[0.2em] leading-none mb-1">SECRETARÍA ACADÉMICA</p>
              <h1 className="font-bold text-lg tracking-tight text-white uppercase">VERIFICADOR DE REQUISITOS</h1>
            </div>
          </div>

          <div className="flex items-center gap-4 relative z-10">
            {/* Navigation Tabs */}
            <nav className="hidden md:flex items-center gap-8 mr-6">
              <button
                onClick={() => setActiveView('individual')}
                className={`text-sm font-bold transition-all flex flex-col items-center gap-1 relative ${
                  activeView === 'individual' 
                    ? 'text-brand-light' 
                    : 'text-white hover:text-brand-light/70'
                }`}
              >
                Resultados individuales
                {activeView === 'individual' && (
                  <motion.div 
                    layoutId="activeTab"
                    className="absolute -bottom-1 left-0 right-0 h-0.5 bg-brand-light shadow-[0_0_8px_#00d1ff]"
                  />
                )}
              </button>
              <button
                onClick={() => setActiveView('summary')}
                className={`text-sm font-bold transition-all flex flex-col items-center gap-1 relative ${
                  activeView === 'summary' 
                    ? 'text-brand-light' 
                    : 'text-white hover:text-brand-light/70'
                }`}
              >
                Resumen
                {activeView === 'summary' && (
                  <motion.div 
                    layoutId="activeTab"
                    className="absolute -bottom-1 left-0 right-0 h-0.5 bg-brand-light shadow-[0_0_8px_#00d1ff]"
                  />
                )}
              </button>
            </nav>

            <button 
              onClick={resetAll}
              className="p-2 text-white/50 hover:text-brand-light transition-colors"
              title="Reiniciar"
            >
              <RotateCcw size={18} />
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-[1400px] w-full mx-auto p-4 flex-1 flex flex-col">
        {activeView === 'individual' ? (
          <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 flex-1">
          
          {/* Sidebar: File List */}
          <motion.div 
            initial={{ opacity: 0, x: -20 }}
            animate={{ opacity: 1, x: 0 }}
            transition={{ duration: 0.5, ease: "easeOut" }}
            className="lg:col-span-3 sticky top-24 self-start h-[calc(100vh-120px)]"
          >
            <div className={`bg-box-light rounded-2xl border border-white/10 shadow-2xl flex flex-col transition-all duration-300 h-full`}>
              <div className="p-4 border-b border-dark/5 bg-dark/5 flex items-center justify-between">
                <h2 className="text-xs font-bold text-brand uppercase tracking-widest">Anexos ({files.length})</h2>
                <button 
                  onClick={() => fileInputRef.current?.click()}
                  className="p-1.5 bg-brand-light text-dark rounded-lg hover:bg-white transition-all shadow-lg"
                >
                  <Plus className="w-4 h-4" />
                </button>
              </div>

              <input 
                type="file" 
                ref={fileInputRef} 
                onChange={handleFileChange} 
                accept=".pdf" 
                multiple
                className="hidden" 
              />

              <div className="flex-1 overflow-y-auto p-2 space-y-0.5 custom-scrollbar">
                {files.length === 0 ? (
                  <div className="h-full flex flex-col items-center justify-center p-6 text-center">
                    <p className="text-xs font-black text-dark/70 uppercase tracking-widest">0 registros cargados</p>
                  </div>
                ) : (
                  files.map((f, index) => (
                    <motion.div 
                      key={f.id}
                      initial={{ opacity: 0, y: 10 }}
                      animate={{ opacity: 1, y: 0 }}
                      transition={{ delay: index * 0.05 }}
                      onClick={() => setSelectedId(f.id)}
                      className={`
                        group px-3 py-1.5 rounded-md transition-all cursor-pointer flex items-center justify-between border-l-2
                        ${selectedId === f.id 
                          ? 'bg-brand-light/20 border-brand-light text-dark' 
                          : 'bg-transparent border-transparent hover:bg-dark/5 text-dark/50'}
                      `}
                    >
                      <div className="flex items-center gap-2 overflow-hidden">
                        {f.loading ? (
                          <Loader2 className="w-2.5 h-2.5 animate-spin flex-shrink-0" />
                        ) : f.result ? (
                          isComplete(f.result) ? (
                            <CheckCircle2 className="w-2.5 h-2.5 flex-shrink-0 text-emerald-600" />
                          ) : (
                            <AlertCircle className="w-2.5 h-2.5 flex-shrink-0 text-amber-600" />
                          )
                        ) : f.error ? (
                          <XCircle className="w-2.5 h-2.5 flex-shrink-0 text-rose-600" />
                        ) : (
                          <FileText className="w-2.5 h-2.5 flex-shrink-0 opacity-20" />
                        )}
                        <div className="truncate">
                          <p className="text-[11px] font-bold truncate uppercase tracking-tight">
                            {f.studentName}
                          </p>
                        </div>
                      </div>
                      <button 
                        onClick={(e) => { e.stopPropagation(); removeFile(f.id); }}
                        className="p-0.5 rounded opacity-0 group-hover:opacity-100 transition-all text-dark/20 hover:text-rose-600 hover:bg-dark/5"
                      >
                        <Trash2 className="w-2.5 h-2.5" />
                      </button>
                    </motion.div>
                  ))
                )}
              </div>

              {files.length > 0 && (
                <div className="p-4 bg-dark/5 border-t border-dark/5">
                  <button
                    disabled={isBatchProcessing || files.length === 0}
                    onClick={analyzeAll}
                    className={`
                      w-full py-3 px-4 rounded-xl font-bold text-sm flex items-center justify-center gap-2 transition-all
                      ${isBatchProcessing || files.length === 0
                        ? 'bg-dark/10 text-dark/30 cursor-not-allowed' 
                        : 'bg-brand-light text-dark hover:bg-white shadow-lg shadow-brand-light/20'}
                    `}
                  >
                    {isBatchProcessing ? (
                      <>
                        <Loader2 className="w-4 h-4 animate-spin" />
                        PROCESANDO...
                      </>
                    ) : (
                      <>
                        <CheckCircle2 className="w-4 h-4" />
                        ANALIZAR TODO
                      </>
                    )}
                  </button>
                </div>
              )}
            </div>
          </motion.div>

          {/* Main Content: Results */}
          <motion.div 
            initial={{ opacity: 0, x: 20 }}
            animate={{ opacity: 1, x: 0 }}
            transition={{ duration: 0.5, ease: "easeOut" }}
            className="lg:col-span-9 flex flex-col"
          >
            <AnimatePresence mode="wait">
              {!selectedFile ? (
                <motion.div 
                  initial={{ opacity: 0, y: 10 }}
                  animate={{ opacity: 1, y: 0 }}
                  onClick={() => fileInputRef.current?.click()}
                  className={`min-h-[500px] flex-1 flex flex-col items-center justify-center rounded-2xl shadow-2xl transition-all duration-300 group border-2 relative overflow-hidden ${
                    isDragging 
                      ? 'bg-box-light border-brand border-dotted scale-[1.02] animate-pulse' 
                      : 'bg-box-light border-dark/10 border-dashed text-dark/40 cursor-pointer hover:border-brand-light/30'
                  }`}
                >
                  <div className={`relative z-10 w-20 h-20 rounded-full flex items-center justify-center mb-6 transition-all duration-300 ${isDragging ? 'bg-brand-light text-dark scale-110' : 'bg-dark/5 text-dark/20 group-hover:scale-110 group-hover:bg-brand-light/10 group-hover:text-brand-light'}`}>
                    <Upload className="w-8 h-8" />
                  </div>
                  <h3 className={`relative z-10 text-xl font-bold transition-colors duration-300 tracking-tight ${isDragging ? 'text-brand' : 'text-brand group-hover:text-brand'}`}>
                    {isDragging ? 'Suelte los archivos aquí' : 'Anexos'}
                  </h3>
                  <p className={`text-xs max-w-xs text-center mt-3 transition-colors duration-300 ${isDragging ? 'text-dark/80' : 'text-dark/60'}`}>
                    {isDragging ? 'Iniciando carga automática...' : 'Haz clic aquí o arrastra tus documentos PDF para comenzar la verificación automática.'}
                  </p>
                  {!isDragging && (
                    <div className="mt-8 px-8 py-3 bg-brand-light text-dark rounded-full font-bold text-[10px] tracking-widest uppercase shadow-xl hover:bg-white transition-all">
                      Seleccionar Archivos
                    </div>
                  )}
                </motion.div>
              ) : selectedFile.loading ? (
                <motion.div 
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 1 }}
                  className="min-h-[400px] flex-1 flex flex-col items-center justify-center bg-box-light border border-white/10 rounded-2xl shadow-2xl"
                >
                  <div className="relative mb-6">
                    <div className="w-20 h-20 border-4 border-dark/5 rounded-full"></div>
                    <div className="w-20 h-20 border-4 border-brand-light rounded-full border-t-transparent animate-spin absolute top-0 left-0"></div>
                  </div>
                  <h3 className="text-xl font-bold text-brand">Analizando Anexo</h3>
                  <p className="text-sm text-dark/40 mt-2">Extrayendo información de {selectedFile.file.name}...</p>
                </motion.div>
              ) : selectedFile.error ? (
                <motion.div 
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 1 }}
                  className="min-h-[400px] flex-1 flex flex-col items-center justify-center bg-box-light border border-rose-500/20 rounded-2xl shadow-2xl"
                >
                  <div className="w-20 h-20 bg-rose-500/10 rounded-full flex items-center justify-center mb-4 text-rose-600">
                    <AlertCircle className="w-10 h-10" />
                  </div>
                  <h3 className="text-xl font-bold text-rose-600">Error de Procesamiento</h3>
                  <p className="text-sm text-dark/60 mt-2">{selectedFile.error}</p>
                  <button 
                    onClick={() => analyzeFile(selectedFile.id)}
                    className="mt-6 px-8 py-3 bg-rose-500 text-white rounded-full font-bold text-sm shadow-lg shadow-rose-500/20 hover:bg-rose-600 transition-all"
                  >
                    REINTENTAR ANÁLISIS
                  </button>
                </motion.div>
              ) : selectedFile.result ? (
                isComplete(selectedFile.result) ? (
                  <motion.div 
                    initial={{ opacity: 0 }}
                    animate={{ opacity: 1 }}
                    className="min-h-[400px] flex-1 flex flex-col items-center justify-center bg-box-light border border-white/10 rounded-2xl shadow-2xl"
                  >
                    <div className="w-20 h-20 bg-emerald-500/10 rounded-full flex items-center justify-center mb-4 text-emerald-600">
                      <CheckCircle2 className="w-10 h-10" />
                    </div>
                    <h3 className="text-xl font-bold text-brand tracking-tight">{selectedFile.result.personName}</h3>
                    <p className="text-sm text-dark/60 mt-2 font-bold uppercase tracking-widest">Sin novedades detectadas</p>
                    <p className="text-xs text-dark/40 mt-1">Este estudiante tiene todos sus requisitos completos.</p>
                    <button
                      onClick={() => handleDownloadReordered(selectedFile)}
                      className="mt-6 px-8 py-3 bg-brand-light text-dark rounded-full text-xs font-bold hover:bg-brand transition-all flex items-center gap-2 shadow-lg shadow-brand-light/20"
                    >
                      <Download className="w-4 h-4" />
                      DESCARGAR PDF ORDENADO
                    </button>
                  </motion.div>
                ) : (
                  <motion.div 
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    className="flex-1"
                  >
                  {/* Header Info - Compact */}
                  <div className="mb-6">
                    <div className="bg-white rounded-2xl border border-white/10 p-5 shadow-2xl relative overflow-hidden">
                      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 relative z-10">
                        <div className="flex items-center gap-6">
                          <div className="flex flex-col gap-1">
                            <p className="text-[16px] font-bold text-black">
                              Programa: {selectedFile.result.academicProgram || 'No detectado'}
                            </p>
                            <p className="text-[18px] font-bold text-[#132e89]">
                              Estudiante: {selectedFile.result.personName}
                            </p>
                            <p className={`text-[12px] font-normal ${selectedFile.responsible === 'NO HAY RESPONSABLE' ? 'text-rose-600' : 'text-black'}`}>
                              Responsable: {selectedFile.responsible}
                            </p>
                          </div>
                        </div>
                        
                        <div className="flex flex-col gap-3">
                          <button
                            onClick={() => handleDownloadReordered(selectedFile)}
                            className="px-6 py-2 bg-brand-light text-dark rounded-full text-[10px] font-bold hover:bg-brand transition-all flex items-center justify-center gap-2 shadow-lg shadow-brand-light/20"
                          >
                            <Download className="w-3.5 h-3.5" />
                            EXPORTAR PDF ORDENADO
                          </button>
                        </div>
                      </div>
                    </div>
                  </div>

                  {/* Checklist Grid */}
                  <div className="bg-box-light rounded-2xl border border-white/10 shadow-2xl overflow-hidden flex flex-col mb-6">
                    <div className="px-8 py-4 bg-white border-b border-dark/5">
                      <h3 className="font-bold text-[#132e89] text-[16px] font-arial uppercase tracking-widest">DETALLE DE REQUISITOS</h3>
                    </div>
                    
                    <div className="divide-y divide-dark/5">
                      <div className="divide-y divide-dark/5">
                        {selectedFile.result.checklist.map((item, idx) => (
                          <motion.div 
                            key={idx} 
                            initial={{ opacity: 0, x: 10 }}
                            animate={{ opacity: 1, x: 0 }}
                            transition={{ delay: idx * 0.03 }}
                            className="px-8 py-2 hover:bg-dark/5 transition-all group cursor-default"
                          >
                            <div className="flex items-center justify-between gap-5">
                              <div className="flex-1 min-w-0">
                                <h4 className="text-[13px] font-normal text-black truncate leading-tight">{item.item}</h4>
                              </div>
                              <div className="flex items-center gap-4 flex-shrink-0">
                                <div className="flex items-center gap-3">
                                  <span className={`text-[12px] font-bold uppercase tracking-tight ${item.status === 'present' ? 'text-black' : 'text-rose-600'}`}>
                                    {item.foundValue ? item.foundValue.toUpperCase() : 'NO DETECTADO'}
                                  </span>
                                  {item.status === 'present' ? (
                                    <CheckCircle2 className="w-6 h-6 text-emerald-600 drop-shadow-sm" />
                                  ) : (
                                    <XCircle className="w-6 h-6 text-rose-600 drop-shadow-sm" />
                                  )}
                                </div>
                              </div>
                            </div>
                          </motion.div>
                        ))}
                      </div>

                      {/* Additional Documents Section - Integrated into scroll */}
                      {selectedFile.result.additionalDocuments.length > 0 && (
                        <div className="p-8 border-t border-dark/5 bg-dark/5">
                          <div className="flex items-center gap-3 mb-6">
                            <div className="w-10 h-10 bg-amber-500/10 rounded-xl flex items-center justify-center text-amber-600">
                              <FilePlus className="w-6 h-6" />
                            </div>
                            <div>
                              <h3 className="font-bold text-brand text-[15px]">Anexos Detectados</h3>
                              <p className="text-[10px] text-dark/40">Documentos adicionales no requeridos en el checklist oficial</p>
                            </div>
                          </div>
                          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3">
                            {selectedFile.result.additionalDocuments.map((doc, idx) => (
                              <div key={idx} className="flex items-center gap-3 p-4 bg-white rounded-xl border border-dark/5 hover:border-brand-light/20 transition-all group">
                                <FileText className="w-5 h-5 text-dark/20 group-hover:text-brand-light transition-colors" />
                                <span className="text-[10px] font-bold text-dark/60 truncate">{doc}</span>
                              </div>
                            ))}
                          </div>
                        </div>
                      )}
                    </div>
                  </div>
                </motion.div>
              )) : (
                <motion.div 
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 1 }}
                  className="min-h-[400px] flex-1 flex flex-col items-center justify-center bg-box-light border border-white/10 rounded-2xl shadow-2xl"
                >
                  <div className="w-20 h-20 bg-dark/5 rounded-full flex items-center justify-center mb-4 text-dark/20">
                    <Clock className="w-10 h-10 animate-pulse" />
                  </div>
                  <h3 className="text-xl font-bold text-brand tracking-tight">{selectedFile.studentName}</h3>
                  <p className="text-sm text-dark/40 mt-2 font-bold uppercase tracking-widest">Pendiente de Análisis</p>
                  <p className="text-xs text-dark/20 mt-1 italic">Haz clic en "Analizar Todo" para procesar los archivos cargados.</p>
                </motion.div>
              )}
            </AnimatePresence>
          </motion.div>
        </div>
      ) : (
        /* Summary View */
        <motion.div 
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          className="bg-box-light rounded-2xl border border-white/10 shadow-2xl overflow-hidden flex flex-col transition-all duration-300 flex-1 min-h-0"
        >
          <div className="px-8 py-6 border-b border-dark/5 bg-white flex items-center">
            <h3 className="flex-1 font-bold text-brand uppercase tracking-widest text-sm">RESUMEN GENERAL DE REQUISITOS</h3>
            <div className="w-[16%] flex justify-center">
              <button 
                onClick={downloadAllZip}
                disabled={files.length === 0 || isDownloadingZip}
                className="flex items-center gap-2 px-6 py-2 bg-brand-light text-dark rounded-full font-bold text-[10px] uppercase tracking-widest shadow-lg shadow-brand-light/20 hover:bg-brand transition-all disabled:opacity-50 disabled:cursor-not-allowed"
              >
                {isDownloadingZip ? (
                  <>
                    <Loader2 className="w-4 h-4 animate-spin" />
                    Descargando...
                  </>
                ) : (
                  <>
                    <Archive className="w-4 h-4" />
                    Descargar Todo
                  </>
                )}
              </button>
            </div>
          </div>
          <div className={`flex-1 overflow-x-auto ${files.length === 0 ? 'overflow-y-hidden' : 'overflow-y-auto custom-scrollbar'}`}>
            <table className="w-full text-left border-collapse table-fixed">
              <thead>
                <tr className="bg-dark/5 border-b border-dark/5">
                  <th className="w-[28%] px-8 py-4 text-[12px] font-black text-[#002cb8] uppercase tracking-widest">Programa</th>
                  <th className="w-[28%] px-8 py-4 text-[12px] font-black text-[#002cb8] uppercase tracking-widest">Estudiante</th>
                  <th className="w-[28%] px-8 py-4 text-[12px] font-black text-[#002cb8] uppercase tracking-widest">Responsable</th>
                  <th className="w-[16%] px-8 py-4 text-[12px] font-black text-[#002cb8] uppercase tracking-widest text-center">Novedades</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-dark/5">
                {files.length === 0 ? (
                  <tr>
                    <td colSpan={4} className="px-8 py-20 text-center">
                      <div className="flex flex-col items-center justify-center gap-4 mx-auto w-full">
                        <div className="w-16 h-16 bg-dark/5 rounded-2xl flex items-center justify-center text-dark/20">
                          <Files className="w-8 h-8" />
                        </div>
                        <div className="text-center">
                          <p className="text-dark/60 font-bold tracking-widest text-sm">No hay anexos cargados</p>
                          <p className="text-dark/40 text-xs mt-1">Carga archivos en la pestaña de resultados para ver el resumen.</p>
                        </div>
                        <button 
                          onClick={() => {
                            setActiveView('individual');
                            setTimeout(() => fileInputRef.current?.click(), 100);
                          }}
                          className="mt-4 px-8 py-3 bg-brand-light text-dark rounded-full font-bold text-xs tracking-widest uppercase shadow-lg shadow-brand-light/20 hover:bg-brand transition-all"
                        >
                          Cargar Archivos Ahora
                        </button>
                      </div>
                    </td>
                  </tr>
                ) : (
                  files.map((f, index) => (
                    <motion.tr 
                      key={f.id} 
                      initial={{ opacity: 0, y: 10 }}
                      animate={{ opacity: 1, y: 0 }}
                      transition={{ delay: index * 0.05 }}
                      className="hover:bg-dark/5 transition-colors"
                    >
                      <td className="px-8 py-4">
                        <span className="text-[13px] text-black font-normal uppercase block break-words">
                          {f.result ? f.result.academicProgram : 'PENDIENTE'}
                        </span>
                      </td>
                      <td className="px-8 py-4">
                        <span className="text-[13px] text-black font-normal uppercase block break-words">
                          {f.result ? f.result.personName : f.studentName}
                        </span>
                      </td>
                      <td className="px-8 py-4">
                        <span className={`text-[13px] uppercase block break-words font-normal ${f.responsible === 'NO HAY RESPONSABLE' ? 'text-rose-600' : 'text-black'}`}>
                          {f.responsible || 'PENDIENTE'}
                        </span>
                      </td>
                      <td className="px-8 py-4">
                        <div className="flex justify-center items-center gap-4">
                          {f.loading ? (
                            <Loader2 className="w-5 h-5 text-brand-light animate-spin" />
                          ) : f.error ? (
                            <div className="flex items-center gap-2 text-amber-600 bg-amber-600/10 px-3 py-1 rounded-full border border-amber-600/20">
                              <AlertCircle className="w-4 h-4" />
                              <span className="text-[10px] font-black uppercase">ERROR</span>
                            </div>
                          ) : f.result ? (
                            <button 
                              onClick={() => {
                                setSelectedId(f.id);
                                setActiveView('individual');
                              }}
                              className={`shrink-0 flex items-center gap-1 px-3 py-1 rounded-lg text-[10px] font-bold uppercase tracking-widest transition-all bg-[#f1b5c9] ${
                                isComplete(f.result) 
                                  ? 'text-emerald-600 hover:bg-[#f1b5c9]/80' 
                                  : 'text-rose-600 hover:bg-[#f1b5c9]/80'
                              }`}
                            >
                              {isComplete(f.result) ? 'Sin Novedades' : 'Ver Novedades'}
                              <ChevronRight className="w-3 h-3" />
                            </button>
                          ) : (
                            <span className="text-[10px] font-bold text-dark/20 uppercase">SIN ANALIZAR</span>
                          )}
                        </div>
                      </td>
                    </motion.tr>
                  ))
                )}
              </tbody>
            </table>
          </div>
        </motion.div>
      )}
      </main>

      <footer className="max-w-[1400px] w-full mx-auto px-6 py-4 flex flex-col items-center justify-center gap-2 text-white/40 text-[9px] font-bold uppercase tracking-[0.2em] bg-transparent shrink-0">
        <span>© 2016 - OFICINA DE ESTADÍSTICA DE LA ESCUELA NAVAL DE CADETES "ALMIRANTE PADILLA".</span>
      </footer>
    </div>
  );
}
